CREATE PROCEDURE delete_inactive_users()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE user_id INT;
    DECLARE cursor user_cursor;
    DECLARE continue_handler INT DEFAULT 1;

    -- Declare the cursor to fetch all users with status 'Inactive'
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    OPEN user_cursor;

    user_loop: LOOP
        FETCH user_cursor INTO user_id;
        IF done = 1 THEN
            LEAVE user_loop;
        END IF;

        -- Check if the user is inactive
        IF (SELECT status FROM users WHERE user_id = user_id) = 'Inactive' THEN
            -- Begin a transaction
            START TRANSACTION;

            -- Delete the user from the users table
            DELETE FROM users WHERE user_id = user_id;

            -- Insert into status_log
            INSERT INTO status_log (user_id, status, modification_date)
            VALUES (user_id, 'Inactive', NOW());

            COMMIT;
        END IF;
    END LOOP;

    CLOSE user_cursor;
END$$

DELIMITER ;
